using System.Collections;
using UnityEngine;

/// <summary>
/// Camuflagem (Suricata, Raposa-do-ártico, Urso Panda — P5): durante
/// "camoDuration" (P1), o player conta como Furtivo para TODOS os inimigos —
/// EnemyDetection ignora-o, excepto inimigos que detectam furtivos
/// (stealthDetection/canBeIgnoredByStealth — Etapa 8.1).
///
/// Activado via PrimaryAbility.Camo (AbilityRouter.OnAbilityPressed → TryCamo).
/// Mover-se NÃO quebra a camuflagem por defeito ("breakOnAttack" cobre o
/// ataque). Feedback visual: alpha do sprite reduzido.
/// </summary>
public class CamoAbility : MonoBehaviour, IFormAbility, IAbility, IActiveAbility
{
    [Header("Visual")]
    [Tooltip("Alpha do sprite enquanto camuflado (feedback simples).")]
    [Range(0.1f, 1f)] public float camoAlpha = 0.4f;

    [Tooltip("SpriteRenderer do player (auto-detectado se vazio).")]
    [SerializeField] private SpriteRenderer spriteRenderer;

    [Header("Regras")]
    [Tooltip("Atacar quebra a camuflagem (PlayerAttack/AbilityRouter chama BreakCamo).")]
    public bool breakOnAttack = true;

    private bool enabledForForm;
    private float duration = 4f;
    private float cooldown = 6f;
    private float cooldownTimer;
    private Coroutine routine;

    /// <summary>true enquanto a camuflagem está activa (lido por EnemyDetection).</summary>
    public bool IsCamoActive { get; private set; }

    private void Awake()
    {
        if (spriteRenderer == null) spriteRenderer = GetComponentInChildren<SpriteRenderer>();
    }

    private void Update()
    {
        if (cooldownTimer > 0f) cooldownTimer -= Time.deltaTime;
    }

    public void ConfigureFromForm(AnimalFormData form)
    {
        enabledForForm = form != null && (form.canCamo || form.primaryAbility == PrimaryAbility.Camo);
        duration = form != null ? Mathf.Max(0.5f, form.camoDuration) : 4f;
        cooldown = form != null ? Mathf.Max(0f, form.camoCooldown) : 6f;

        // Trocar de forma quebra a camuflagem.
        BreakCamo();
    }

    /// <summary>Activa a camuflagem (AbilityRouter — PrimaryAbility.Camo).</summary>
    public void TryCamo()
    {
        if (!enabledForForm || IsCamoActive) return;
        if (cooldownTimer > 0f) return;

        if (routine != null) StopCoroutine(routine);
        routine = StartCoroutine(CamoRoutine());
    }

    /// <summary>Quebra a camuflagem imediatamente (atacar, trocar de forma, tomar dano...).</summary>
    public void BreakCamo()
    {
        if (routine != null)
        {
            StopCoroutine(routine);
            routine = null;
        }

        if (!IsCamoActive) return;

        IsCamoActive = false;
        ApplyAlpha(1f);
        cooldownTimer = cooldown;
    }

    private IEnumerator CamoRoutine()
    {
        IsCamoActive = true;
        ApplyAlpha(camoAlpha);

        yield return new WaitForSeconds(duration);

        routine = null;
        BreakCamo();
    }

    private void ApplyAlpha(float alpha)
    {
        if (spriteRenderer == null) return;

        var color = spriteRenderer.color;
        color.a = alpha;
        spriteRenderer.color = color;
    }

    // ---- IAbility / IActiveAbility (Tarefa #34 — HUD) ----
    // Activate dispara TryCamo (auto-termina após "duration"); Release
    // não tem efeito (não é "hold"); Cancel quebra a camuflagem já.
    void IAbility.Activate() => TryCamo();
    void IAbility.Release() { }
    public void Cancel(AbilityCancelReason reason) => BreakCamo();
    public float CooldownRemaining => Mathf.Max(0f, cooldownTimer);
    bool IAbility.IsActive => IsCamoActive;
    public float CooldownDuration => cooldown;
    public bool CanActivate => enabledForForm && !IsCamoActive && cooldownTimer <= 0f;

    /// <summary>AnimalsDebugPanel — zera o cooldown da camuflagem.</summary>
    public void ResetCooldown() => cooldownTimer = 0f;
}
